import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { createJobPosition, fetchAllDepartmentData, fetchJobPositionById, updateJobPosition } from 'src/components/services/CareerApi';
import { CCol, CForm, CButton, CFormLabel } from '@coreui/react';
import FormInput from 'src/utils/FormInput';
import Select from 'react-select';
import authService from 'src/auth/auth.service';
import GoBackComponent from 'src/utils/GoBackComponent';

function JobPositionForm(props) {
  const { type, id } = props;
  const [userData] = useState(authService.getUserDetailsFromLocalStorage());
  const [formData, setFormData] = useState({ title: '', departmentId: '' });
  const [errors, setErrors] = useState({});
  const [errorMessage, setErrorMessage] = useState('');
  const [departmentOption, setDepartmentOption] = useState([]);
  const [department, setDepartment] = useState({});

  const navigate = useNavigate();

  useEffect(() => {
    if (type === 'EDIT') {
      fetchJobPositionDataById(id);
    }
    getAllDepartments();
  }, []);

  const handleChange = (event) => {
    setFormData({ ...formData, [event.target.name]: event.target.value.trimStart().replace(/ +/g, ' ') });
  };

  const fetchJobPositionDataById = async (id) => {
    let response = await fetchJobPositionById(id);
    if (response?.code === 200) {
      let responseData = response?.results;
      let data = {
        title: responseData?.title,
        departmentId: responseData?.departmentId?._id,
      };
      setDepartment({ label: responseData?.departmentId?.name, value: responseData?.departmentId?._id });
      setFormData(data);
    }
  };

  const validateForm = () => {
    let errors = {};
    let formIsValid = true;
    if (!formData.title.trim()) {
      errors['title'] = 'Please enter position name';
      formIsValid = false;
    }
    if (!department.value) {
      errors['departmentId'] = 'Please select department';
      formIsValid = false;
    }

    setErrors(errors);
    setTimeout(() => {
      setErrors({});
    }, 2000);
    return formIsValid;
  };

  const handleSubmit = async (event) => {
    event.preventDefault();
    if (validateForm()) {
      let postData = {
        title: formData.title,
        departmentId: department.value,
      };
      let response = {};
      if(type === "CREATE") {
        response = await createJobPosition(postData);
      } else {
        postData.id = id;
        response = await updateJobPosition(postData);
      }
      if (response?.code === 201 || response?.code === 202) {
        navigate('/career/position');
      }
      if (response?.code === 409) {
        setErrorMessage(response?.message);
      }
    }
    setTimeout(() => {
      setErrors({});
    }, 2000);
  };

  const getAllDepartments = async () => {
    let departments = [];
    let response = await fetchAllDepartmentData();
    if (response?.code === 200) {
      const sortDepartment = response && response?.results.sort((a, b) => new Date(b.createdAt) - new Date(a.createdAt))
      const updateData = sortDepartment.filter(item => item.status === "ENABLE");
      updateData && updateData.map((data) => {
        departments.push({ label: data.name, value: data._id });
      });
      setDepartmentOption(departments);
    }
  };

  const handleChangeDepartment = (department) => {
    setDepartment(department);
  };

  return (
    <>
      <GoBackComponent goBackData={"career/position"} />
      <div className='customContainer'>
        <CForm className='row g-3'>
        <CCol md={6}>
            <div className='form-group'>
              <CFormLabel htmlFor='exampleFormControlTextarea1'>
                Select Department <span className='text-danger'>*</span>
              </CFormLabel>
              <Select
                placeholder={'Select type'}
                className='wnforSelect'
                name={'userFilterOption'}
                options={departmentOption}
                value={department}
                onChange={handleChangeDepartment}
                classNamePrefix="select"
                styles={{
                  option: (styles, { data, isDisabled, isFocused, isSelected }) => {
                    const color = '#03a68059';
                    return {
                      ...styles,
                      backgroundColor: isDisabled
                        ? null
                        : isSelected
                          ? '#03a68059'
                          : isFocused
                            ? '#03a68059'
                            : null,
                      color: isDisabled
                        ? '#ccc'
                        : isSelected
                          ? color > 2
                            ? '#00374d'
                            : '#00374d'
                          : data.color,
                      cursor: isDisabled ? 'not-allowed' : 'default',

                      ':active': {
                        ...styles[':active'],
                        backgroundColor: !isDisabled && (isSelected ? '#03a68059' : '#03a68059'),
                      },
                    };
                  },
                }}
              />
              {errors['departmentId'] && <div className='text-danger'>{errors['departmentId']}</div>}
            </div>
          </CCol>
          <CCol md={12}>
            <FormInput
              value={formData.title}
              label={'Position Title'}
              name={'title'}
              required
              onChange={handleChange}
              error={errors['title']}
            />
          </CCol>
          {errorMessage && <span style={{ color: "red" }}>{errorMessage}</span>}
          {authService.getPermission(props.type === "CREATE" ? "CAREER_POSITION_CREATE" : "CAREER_POSITION_UPDATE") && 
            <CCol md={12}>
              <CButton color='primary' onClick={handleSubmit} className='d-block'>
                {props.type === 'CREATE' ? 'Create' : 'Update'}
              </CButton>
            </CCol>
          }
        </CForm>
      </div>
    </>
  );
}

export default JobPositionForm;
